import React from "react";

type TRating = {
  review: number;
  isReadOnly?: boolean;
  name: string;
};

const Rating = ({ review, isReadOnly = false, name }: TRating) => {
  const stars = [1, 2, 3, 4, 5];
  return (
    <div className="rating">
      {isReadOnly &&
        stars.map((star) =>
          star === review ? (
            <input
              key={star}
              type="radio"
              name="rating"
              className="mask mask-star-2 bg-orange-400"
              checked
              disabled
            />
          ) : (
            <input
              key={star}
              type="radio"
              name="rating-2"
              className="mask mask-star-2 bg-orange-400"
              disabled
            />
          )
        )}
      {!isReadOnly &&
        stars.map((star) =>
          star === review ? (
            <input
              key={star}
              type="radio"
              name="rating"
              className="mask mask-star-2 bg-orange-400"
              checked
            />
          ) : (
            <input
              key={star}
              type="radio"
              name="rating-2"
              className="mask mask-star-2 bg-orange-400"
            />
          )
        )}
    </div>
  );
};

export default Rating;
